import{_ as t,o,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"21. Redeployment Former S97. Employees","description":"","frontmatter":{"title":"21. Redeployment Former S97. Employees","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/consultation-disputes/21-redeployment-former-s97-employees.md","filePath":"ebas/mental-health/common-terms/consultation-disputes/21-redeployment-former-s97-employees.md"}'),n={name:"ebas/mental-health/common-terms/consultation-disputes/21-redeployment-former-s97-employees.md"};function s(l,e,i,p,d,m){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_21-redeployment-former-s97-employees" tabindex="-1">21. Redeployment Former S97. Employees <a class="header-anchor" href="#_21-redeployment-former-s97-employees" aria-label="Permalink to &quot;21. Redeployment Former S97. Employees&quot;">​</a></h1><p><strong>21.1</strong> An Employee who was a s97 Employee as at 19 December 1997, who transferred to an Employer on or after 19 December 1997 and has been continuously employed by the same Employer since the date of transfer in the same position, and who is redeployed as a result of their position being made redundant to a position having a lower salary than the salary of their former position, must be paid</p><p>a salary which is not less than the actual salary of the Employee at the date of redeployment adjusted from time to time in accordance with this Agreement and adjusted to reflect each incremental step through the former classification on the anniversary of each increment.</p><p><strong>21.2</strong> An Employee covered by this clause must be paid:</p><p><strong>(a)</strong> for a period of twelve months from the date of transfer a total emolument which is not less than the salary payable immediately prior to the date of transfer and the all-purpose allowances paid to the Employee over the preceding twelve months</p><p><strong>(b)</strong> for the purposes of this subclause all-purpose allowances means:</p><p><strong>(i)</strong> Any allowance (other than a higher duties allowance) which an Employee would have been entitled to be paid whilst on recreation leave; and</p><p><strong>(ii)</strong> Roster and shift allowances paid to the Employee during the twelve months immediately preceding the day of transfer.</p><p><strong>21.3</strong> Salary - full-time Employee The ordinary salary for a full-time Employee shall be their applicable salary in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>, excluding allowances.</p><p><strong>21.4</strong> Hourly rate - full-time Employee The ordinary hourly rate for a full-time Employee shall be their applicable ordinary weekly salary divided by 38.</p><p><strong>21.5</strong> Hourly rate - part-time Employee The ordinary weekly salary and ordinary hourly rate for a part-time Employee shall be calculated on a pro rata basis of a full-time Employee.</p><p><strong>21.6</strong> Disturbance allowance</p><p><strong>(a)</strong> An Employee who was a s97 Employee as at 19 December 1997, who transferred to an Employer on or after 19 December 1997 and has been continuously employed by the same Employer since the date of transfer in the same position, and who is redeployed as a result of their position being made redundant and is redeployed and who is required to travel to a new work location is entitled to be paid a disturbance allowance in compensation for all disturbance factors, which are not otherwise provided for in this agreement.</p><p><strong>(b)</strong> No disturbance allowance will be paid if the redeployed Employee is required to travel less than ten kilometres extra per day.</p><p><strong>(c)</strong> The allowance is paid in the following circumstances:</p><p><strong>(i)</strong> at a rate of $709 if the Employee is required to travel up to an extra 30 minutes or an extra 30 kilometres per day; and</p><p><strong>(ii)</strong> at a rate of $709, for each additional 30 minutes or 30 kilometres or part thereof.</p><p><strong>(d)</strong> An Employee entitled to an allowance under this subclause may, in lieu, elect to be reimbursed all additional travel costs at public transport rates for a period of one year.</p><p><strong>(e)</strong> A redeployed Employee who is not entitled to the disturbance allowance contained in this Agreement but who is required to pay additional travel costs as a result of relocation is entitled to be reimbursed those additional costs at public transport rates for a period of one year.</p><p><strong>(f)</strong> The disturbance allowance may be paid only once in compensation for all disturbance factors incurred by the single transfer.</p><p><strong>(g)</strong> For the avoidance of doubt, the allowances referred to above will not be subject to any increase during the life of this Agreement.</p><p>Plain language terms: redeployment, s97 employee, section 97.</p>',22)])])}const y=t(n,[["render",s]]);export{c as __pageData,y as default};
